const { expect } = require('expect')
const REST = require('../../lib/helper/REST')
const JSONResponse = require('../../lib/helper/JSONResponse')
const Container = require('../../lib/container')

global.codeceptjs = require('../../lib')

describe('onResponse callback preservation', () => {
  it('should preserve user onResponse when JSONResponse overrides it', async () => {
    let userOnResponseCalled = false
    let jsonResponseValue = null

    const restHelper = new REST({
      endpoint: 'http://localhost:3000',
      onResponse: (response) => {
        userOnResponseCalled = true
        response.headers['x-custom'] = 'custom-value'
      },
    })

    // Simulate what JSONResponse._beforeSuite does
    const existingOnResponse = restHelper.config.onResponse

    // Now simulate JSONResponse overriding
    restHelper.config.onResponse = (response) => {
      jsonResponseValue = response
    }

    // User's callback should have been called too
    // This test demonstrates that the existing code loses the user's callback
    const testResponse = { status: 200, headers: {}, data: { ok: true } }

    // Call the overridden onResponse
    restHelper.config.onResponse(testResponse)

    // Verify: user's callback was lost (the bug)
    expect(userOnResponseCalled).toBe(false) // This confirms the bug exists
    expect(jsonResponseValue).toBe(testResponse)
    expect(testResponse.headers['x-custom']).toBeUndefined()
  })

  it('should chain user onResponse with JSONResponse onResponse', async () => {
    let userOnResponseCalled = false
    let jsonResponseValue = null

    const restHelper = new REST({
      endpoint: 'http://localhost:3000',
      onResponse: (response) => {
        userOnResponseCalled = true
        response.headers['x-custom'] = 'custom-value'
      },
    })

    // This is what the fix should do: chain callbacks
    const existingOnResponse = restHelper.config.onResponse
    restHelper.config.onResponse = (response) => {
      if (existingOnResponse) {
        existingOnResponse(response)
      }
      jsonResponseValue = response
    }

    const testResponse = { status: 200, headers: {}, data: { ok: true } }
    restHelper.config.onResponse(testResponse)

    // Verify: both callbacks were called
    expect(userOnResponseCalled).toBe(true)
    expect(jsonResponseValue).toBe(testResponse)
    expect(testResponse.headers['x-custom']).toBe('custom-value')
  })

  it('should work with JSONResponse via Container integration', async () => {
    let userOnResponseCalled = false

    // Simulate user config
    Container.create({
      helpers: {
        REST: {
          endpoint: 'http://localhost:3000',
          onResponse: (response) => {
            userOnResponseCalled = true
            response.headers['x-custom'] = 'custom-value'
          },
        },
        JSONResponse: {},
      },
    })

    const restHelper = Container.helpers('REST')
    const jsonResponse = Container.helpers('JSONResponse')

    // JSONResponse._beforeSuite should chain with the existing onResponse
    jsonResponse._beforeSuite()

    const testResponse = { status: 200, headers: {}, data: { ok: true } }
    restHelper.config.onResponse(testResponse)

    // Verify both work
    expect(userOnResponseCalled).toBe(true)
    expect(testResponse.headers['x-custom']).toBe('custom-value')
    expect(jsonResponse.response).toBe(testResponse)

    Container.clear()
  })
})

